class DirectedGraph:
    def __init__(self, n: int):
        self.n = n
        self.adj = [[] for _ in range(n)]
        self.in_degree = [0] * n

    def add_edge(self, u: int, v: int) -> None:
        self.adj[u].append(v)
        self.in_degree[v] += 1

    def has_cycle(self) -> bool:
        in_deg = list(self.in_degree)
        queue = [i for i in range(self.n) if in_deg[i] == 0]
        count = 0
        idx = 0
        while idx < len(queue):
            u = queue[idx]
            idx += 1
            count += 1
            for v in self.adj[u]:
                in_deg[v] -= 1
                if in_deg[v] == 0:
                    queue.append(v)
        return count < self.n

    def topological_sort(self) -> list[int] | None:
        if self.has_cycle():
            return None
        in_deg = list(self.in_degree)
        queue = [i for i in range(self.n) if in_deg[i] == 0]
        result = []
        idx = 0
        while idx < len(queue):
            u = queue[idx]
            idx += 1
            result.append(u)
            for v in self.adj[u]:
                in_deg[v] -= 1
                if in_deg[v] == 0:
                    queue.append(v)
        return result

    def all_topological_sorts(self) -> list[list[int]]:
        if self.has_cycle():
            return []

        results = []
        in_deg = list(self.in_degree)
        path = []
        used = [False] * self.n

        def backtrack():
            if len(path) == self.n:
                results.append(list(path))
                return

            candidates = []
            for i in range(self.n):
                if in_deg[i] == 0 and not used[i]:
                    candidates.append(i)

            candidates.sort()

            for c in candidates:
                path.append(c)
                used[c] = True

                for v in self.adj[c]:
                    in_deg[v] -= 1

                backtrack()

                for v in self.adj[c]:
                    in_deg[v] += 1

                used[c] = False
                path.pop()

        backtrack()
        return results

    def longest_path(self) -> int:
        if self.has_cycle():
            return -1

        if self.n == 0:
            return 0

        topo = self.topological_sort()
        dist = [0] * self.n
        for u in topo:
            for v in self.adj[u]:
                if dist[v] < dist[u] + 1:
                    dist[v] = dist[u] + 1

        return max(dist)
