from dataclasses import dataclass
from typing import Any, Optional

@dataclass
class Event:
    start: float
    end: float
    title: str
    priority: int  # higher = more important

class Calendar:
    def __init__(self):
        self.events: list[Event] = []

    def add_event(self, event: Event) -> list[Event]:
        if event.start >= event.end:
            raise ValueError("start must be less than end")

        conflicts = [e for e in self.events if e.start < event.end and e.end > event.start]

        if not conflicts:
            self.events.append(event)
            return []

        max_priority = max(e.priority for e in conflicts)

        if event.priority > max_priority:
            modified_removed = []
            for e in conflicts:
                if event.start <= e.start and event.end >= e.end:
                    self.events.remove(e)
                    modified_removed.append(e)
                elif event.start <= e.start:
                    e.end = event.end
                    modified_removed.append(e)
                elif event.end >= e.end:
                    e.start = event.start
                    modified_removed.append(e)
                else:
                    self.events.remove(e)
                    modified_removed.append(e)
                    if event.start > e.start:
                        self.events.append(Event(e.start, event.start, e.title, e.priority))
                    if event.end < e.end:
                        self.events.append(Event(event.end, e.end, e.title, e.priority))
            self.events.append(event)
            return modified_removed
        else:
            merged = self._merge(conflicts)
            fragments = []
            cursor = event.start
            for m in merged:
                if m.start >= event.end:
                    break
                if m.end <= cursor:
                    continue
                if m.start > cursor:
                    gap_end = min(m.start, event.end)
                    if gap_end > cursor:
                        fragments.append(Event(cursor, gap_end, event.title, event.priority))
                        cursor = gap_end
                if m.end > cursor:
                    cursor = m.end
            if cursor < event.end:
                fragments.append(Event(cursor, event.end, event.title, event.priority))

            for f in fragments:
                self.events.append(f)
            return fragments

    def _merge(self, events: list[Event]) -> list[Event]:
        if not events:
            return []
        sorted_ev = sorted(events, key=lambda e: e.start)
        merged = [sorted_ev[0]]
        for e in sorted_ev[1:]:
            last = merged[-1]
            if e.start < last.end:
                last.end = max(last.end, e.end)
            else:
                merged.append(e)
        return merged

    def get_events(self, start: float, end: float) -> list[Event]:
        return sorted([e for e in self.events if e.start < end and e.end > start], key=lambda e: e.start)

    def free_slots(self, start: float, end: float, min_duration: float = 0) -> list[tuple[float, float]]:
        overlaps = [e for e in self.events if e.start < end and e.end > start]
        merged = self._merge(overlaps)

        slots = []
        cursor = start
        for m in merged:
            if m.start >= end:
                break
            if m.end <= cursor:
                continue
            if m.start > cursor:
                gap_end = min(m.start, end)
                if gap_end - cursor >= min_duration:
                    slots.append((cursor, gap_end))
                cursor = gap_end
            if m.end > cursor:
                cursor = m.end

        if cursor < end:
            if end - cursor >= min_duration:
                slots.append((cursor, end))

        return slots

    def utilization(self, start: float, end: float) -> float:
        total = end - start
        if total <= 0:
            return 0.0
        occupied = 0.0
        overlaps = [e for e in self.events if e.start < end and e.end > start]
        merged = self._merge(overlaps)
        for m in merged:
            overlap_start = max(m.start, start)
            overlap_end = min(m.end, end)
            if overlap_end > overlap_start:
                occupied += overlap_end - overlap_start
        return occupied / total
