import hashlib
import bisect

class ConsistentHashRing:
    def __init__(self, num_virtual_nodes: int = 150):
        self.num_virtual_nodes = num_virtual_nodes
        self.ring = []  # List of (hash_int, physical_node_id)

    def _hash(self, s: str) -> int:
        return int(hashlib.md5(s.encode()).hexdigest(), 16)

    def add_node(self, node_id: str) -> None:
        for i in range(self.num_virtual_nodes):
            v_node = f"{node_id}#v{i}"
            h = self._hash(v_node)
            self.ring.append((h, node_id))
        self.ring.sort(key=lambda x: x[0])

    def remove_node(self, node_id: str) -> None:
        if not any(x[1] == node_id for x in self.ring):
            raise KeyError(node_id)
        self.ring = [(h, nid) for h, nid in self.ring if nid != node_id]

    def get_node(self, key: str) -> str | None:
        if not self.ring:
            return None
        h = self._hash(key)
        idx = bisect.bisect_left(self.ring, (h, ""))
        if idx == len(self.ring):
            idx = 0
        return self.ring[idx][1]

    def get_nodes_for_key(self, key: str, num_replicas: int = 3) -> list[str]:
        if not self.ring:
            return []
        h = self._hash(key)
        idx = bisect.bisect_left(self.ring, (h, ""))
        if idx == len(self.ring):
            idx = 0

        nodes = []
        seen = set()
        n = len(self.ring)
        i = idx
        while len(nodes) < num_replicas and len(seen) < n:
            node_id = self.ring[i][1]
            if node_id not in seen:
                nodes.append(node_id)
                seen.add(node_id)
            i = (i + 1) % n
        return nodes
